require "game.ui.window.GUITeamInfo"

local UIBedWarToolBar = class("UIToolBar", IGUILayout)

function UIBedWarToolBar:onLoad()
    -----隐藏旧ToolBar
    GUIManager:getToolBar():SetArea({ 0, 0 }, { 1, 0 }, { 1, 0 }, { 0, 54 })

    self.btnShop = self:getChildWindow("BedWarToolBar-Menu-Shop", GUIType.Button)
    self.cbSetting = self:getChildWindow("BedWarToolBar-Menu-Setting", GUIType.CheckBox)
    self.cbChat = self:getChildWindow("BedWarToolBar-Chat", GUIType.CheckBox)
    self.cbAction = self:getChildWindow("BedWarToolBar-Action", GUIType.CheckBox)
    self.btnChargeCube = self:getChildWindow("BedWarToolBar-Charge", GUIType.Button)
    self.stCubeNum = self:getChildWindow("BedWarToolBar-cube-Num", GUIType.StaticText)
    self.btnChangeCamera = self:getChildWindow("BedWarToolBar-Camera-Change", GUIType.Button)
    self.stKill = self:getChildWindow("BedWarToolBar-ScoreBoard-Info-KillNum", GUIType.StaticText)
    self.btnBackHall = self:getChildWindow("BedWarToolBar-Back-Hall", GUIType.Button)
    self.btnBackHall:SetVisible(false)
    self.btnBackHall:SetText(Lang:getString("gui.backHall"))
    self.btnPlayerAgain = self:getChildWindow("BedWarToolBar-Play-Again", GUIType.Button)
    self.btnPlayerAgain:SetVisible(false)
    self.btnPlayerAgain:SetText(Lang:getString("gui.playAgain"))
    self:register()
end

function UIBedWarToolBar:register()
    self.btnChargeCube:registerEvent(GUIEvent.ButtonClick, function()
        ClientHelper.onRecharge(1)
    end)

    self.btnChangeCamera:registerEvent(GUIEvent.ButtonClick, function()
        local cruCamera = SystemSettingRecord.defaultCamera
        if cruCamera == 1 then
            GUIBedWarSetting:changeCamera(2)
            SystemSettingRecord.defaultCamera = 2
        elseif cruCamera == 2 then
            GUIBedWarSetting:changeCamera(3)
            SystemSettingRecord.defaultCamera = 3
        elseif cruCamera == 3 then
            GUIBedWarSetting:changeCamera(1)
            SystemSettingRecord.defaultCamera = 1
        end
    end)

    self.cbSetting:registerEvent(GUIEvent.CheckStateChanged, function()
        if self.cbSetting:GetChecked() then
            self.cbChat:SetChecked(false)
            self.cbAction:SetChecked(false)
            GUIManager:showWindowByName("Menu.json")
        else
            GUIManager:hideWindowByName("Menu.json")
        end
    end)

    self.btnShop:registerEvent(GUIEvent.ButtonClick, function()

        GUIStore:show(StoreId.CubeStore)
        if BaseMain:getGameType() == "g1046" then
            GameAnalytics:design(1, { "H_clubshop" })
        else
            GameAnalytics:design(1, { "ui_culbshop" })
        end
    end)

    self.cbAction:registerEvent(GUIEvent.CheckStateChanged, function()
        if self.cbAction:GetChecked() then
            self.cbSetting:SetChecked(false)
            self.cbChat:SetChecked(false)
            GUIAction:show()
        else
            GUIAction:hide()
        end
    end)

    self.cbChat:registerEvent(GUIEvent.CheckStateChanged, function()
        if self.cbChat:GetChecked() then
            self.cbSetting:SetChecked(false)
            self.cbAction:SetChecked(false)
            if BaseMain:getGameType() == "g1046" then
                GUIManager:showWindowByName("Chat.json")
            else
                GUIChatInput:show()
            end
        else
            if BaseMain:getGameType() == "g1046" then
                GUIManager:hideWindowByName("Chat.json")
            else
                GUIChatInput:hide()
            end
        end
    end)

    self.btnBackHall:registerEvent(GUIEvent.ButtonClick, function()
        GamePacketSender:sendBackHall()
    end)

    self.btnPlayerAgain:registerEvent(GUIEvent.ButtonClick, function()
        GamePacketSender:sendPlayAgain(Game:getPlatformUserId())
    end)

    self:registerDataCallBack("PlayerLevel", function(level)
        self.level = tonumber(level)
    end)
end

function UIBedWarToolBar:onTick()
    local count = PlayerWallet.getMoneyByCoinId(Define.Money.DIAMOND)
    self.stCubeNum:SetText(tostring(count))

    self.cbSetting:SetChecked(GUIManager:getWindowByName("Menu", GUIType.Layout):IsVisible())
    if BaseMain:getGameType() == "g1046" then
        self.cbChat:SetChecked(GUIManager:getWindowByName("Chat"):IsVisible())
    end
end

function UIBedWarToolBar:onGameStart()
    if self.GameStart then
        return
    end
    self.GameStart = true
    self:createTeamInfo()
    GUIMain:hideList()

    local selfUserId = PlayerManager:getClientPlayer().userId
    self.stKill:SetVisible(true)
    GameInfoManager:registerObserver(tostring(selfUserId), function(info)
        self:updateScoreboard(info)
    end)
end

function UIBedWarToolBar:createTeamInfo()

    local selfUserId = PlayerManager:getClientPlayer().userId
    local clientPlayerInfo = GameInfoManager:getPlayerInfo(selfUserId)
    local selfTeamId = clientPlayerInfo:getValue("teamId")
    --self:createTeamMate(selfUserId, selfTeamId)

    local teamList = { selfTeamId }
    for teamId, _ in pairs(TeamConfig:getTeams()) do
        if tostring(teamId) ~= selfTeamId then
            table.insert(teamList, tostring(teamId))
        end
    end

    ---创建床控件
    local content = self:getChildWindow("BedWarToolBar-TeamInfo-Layout", GUIType.Layout)
    content:CleanupChildren()
    local listBox = IGUIListView.new("BedWarToolBar-TeamInfo-List", content, nil, Orientation.Horizontal)
    listBox.root:SetClipChild(false)
    listBox.root:SetHorizontalAlignment(HorizontalAlignment.Center)
    listBox:setItemSpace(5)
    local teamLayoutWidth = 0
    for index, teamId in pairs(teamList) do
        local teamInfo = GameInfoManager:getTeamInfo(teamId)
        if teamInfo and tonumber(teamInfo:getValue("totalCount")) > 0 then
            local guiTeam = GUITeamInfo.new()
            guiTeam:initTeam(teamId, teamId == selfTeamId)
            guiTeam:updateInfo(teamInfo)
            if GameType == "g1008" then
                guiTeam.root:SetWidth({ 0, 96 })
                teamLayoutWidth = teamLayoutWidth + 101
            else
                guiTeam.root:SetWidth({ 0, 48 })
                teamLayoutWidth = teamLayoutWidth + 53
            end
            guiTeam.root:SetHeight({ 1, 0 })
            listBox:addItem(guiTeam)
        end
        if index == 1 then
            local vsLayout = GUIManager:createGUIWindow(GUIType.Layout, "BedWarToolBar-TeamInfo-VS")
            vsLayout:SetWidth({ 0, 39 })
            vsLayout:SetHeight({ 0, 23 })
            vsLayout:SetVerticalAlignment(VerticalAlignment.Center)
            vsLayout:SetBackImage("set:bedwar_toolbar.json image:VS")
            vsLayout:SetProperty("StretchType", "NineGrid")
            vsLayout:setMaterial(20001)
            listBox.root:AddItem(vsLayout)
        end
    end
    teamLayoutWidth = teamLayoutWidth + 39
    listBox:setArea({ 0, 0 }, { 0, 0 }, { 0, teamLayoutWidth }, { 1, 0 })
end

function UIBedWarToolBar:updateScoreboard(info)
    self.stKill:SetText(info:getValue("kill"))
end

function UIBedWarToolBar:cameraChange()
    local cruCamera = Blockman.Instance():getCurrPersonView()
    if cruCamera == 1 then
        self.btnChangeCamera:SetPushedImage("set:bedwar_toolbar.json image:change_camera_2")
        self.btnChangeCamera:SetNormalImage("set:bedwar_toolbar.json image:change_camera_2")
    elseif cruCamera == 2 then
        self.btnChangeCamera:SetPushedImage("set:bedwar_toolbar.json image:change_camera_3")
        self.btnChangeCamera:SetNormalImage("set:bedwar_toolbar.json image:change_camera_3")
    elseif cruCamera == 0 then
        self.btnChangeCamera:SetPushedImage("set:bedwar_toolbar.json image:change_camera_1")
        self.btnChangeCamera:SetNormalImage("set:bedwar_toolbar.json image:change_camera_1")
    end
end

function UIBedWarToolBar:getPlayerLevel()
    return self.level or 0
end

return UIBedWarToolBar